1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = {
13	  type: string;
14	  material?: string;
15	  enchantment?: number;
16	  cursed?: boolean;
17	};
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
20	
21	const BLOCK_SIZE = 3;
22	const BLOCK_PREMIUM = 60;
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	
25	const groupByType = (items: Item[]): Map<string, Item[]> => {
26	  const groups = new Map<string, Item[]>();
27	  for (const item of items) {
28	    const group = groups.get(item.type) ?? [];
29	    group.push(item);
30	    groups.set(item.type, group);
31	  }
32	  return groups;
33	};
34	
35	const CURSED_RATE = 0.5;
36	
37	const premiumForGroup = (type: string, group: Item[]) => {
38	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
39	    return BLOCK_PREMIUM;
40	  }
41	  return group.length * BASE_PREMIUM[type];
42	};
43	
44	const itemSurcharges = (item: Item) => {
45	  const base = BASE_PREMIUM[item.type];
46	  return item.cursed ? base * CURSED_RATE : 0;
47	};
48	
49	const policyBasePremium = (items: Item[]) =>
50	  [...groupByType(items)].reduce(
51	    (total, [type, group]) => total + premiumForGroup(type, group),
52	    0,
53	  );
54	
55	const sumItemSurcharges = (items: Item[]) =>
56	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
57	
58	const FIRST_INSURANCE_RATE = 0.1;
59	
60	const quote = (step: QuoteStep) => {
61	  const policyBase = policyBasePremium(step.items);
62	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
63	  const itemSurchargeTotal = sumItemSurcharges(step.items);
64	  const premium = policyBase + firstInsurance + itemSurchargeTotal;
65	  return { premium: Math.ceil(premium) + PROCESSING_FEE };
66	};
67	
68	export const run = (input: Scenario): unknown => ({
69	  results: input.steps.map(quote),
70	});
